const results = [];
const rawInputs = $input.all();
const sourceItems = $("Find Posts to Script").all();
const sourceCount = sourceItems.length;

if (sourceCount === 0) return [{ json: { _skip: true } }];

for (let i = 0; i < rawInputs.length; i++) {
  const item = rawInputs[i];
  let raw = item.json.text || item.json.output || '{}';
  let parsed = {};
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    const match = raw.match(/\{[^]*\}/);
    if (match) {
      try { parsed = JSON.parse(match[0]); } catch {}
    }
  }

  // Calculate which source record this script corresponds to.
  const sourceIndex = i % sourceCount;
  const sourceRecord = sourceItems[sourceIndex]?.json || {};

  // RESILIENT MAPPING: Use fallbacks for all critical fields to avoid skipping scripts
  const title = parsed.title || parsed.Name || sourceRecord.Name || 'Untitled Script';
  const platform = parsed.platform || parsed.Target_Platforms || (i < sourceCount ? 'LinkedIn' : 'Facebook');

  results.push({
    json: {
      Name: title,
      Source_Content_ID: sourceRecord.id || sourceRecord.Name || '',
      Script_Title: title,
      Target_Platforms: platform,
      Hook: parsed.hook || '',
      Main_Content: parsed.body || '',
      CTA: parsed.cta || '',
      Status: 'Draft',
      Created_Date: new Date().toISOString().slice(0, 10)
    }
  });
}

return results.length > 0 ? results : [{ json: { _skip: true } }];
